head.b:skin:
/*==========================================================
   PREMIUM CSS CORE VARIABLES (Median UI & Plus UI Style)
==========================================================*/
:root {
  --primary: #0d6efd;
  --primary-rgb: 13, 110, 253;
  --primary-dark: #0b5ed7;
  --secondary: #ff6b00;
  --bg-body: #f4f6fa;
  --bg-card: #ffffff;
  --text-main: #1f2937;
  --text-muted: #6b7280;
  --heading: #111827;
  --border: #e5e7eb;
  --radius-sm: 6px;
  --radius-md: 12px;
  --radius-lg: 20px;
  --shadow: 0 4px 20px rgba(0, 0, 0, 0.04);
  --shadow-hover: 0 10px 30px rgba(13, 110, 253, 0.08);
  --font: 'Plus Jakarta Sans', sans-serif;
  --max-width: 1280px;
}

/* Dark Mode Stylesheet Overrides */
body.dark-mode {
  --bg-body: #0b0f19;
  --bg-card: #151c2c;
  --text-main: #e2e8f0;
  --text-muted: #94a3b8;
  --heading: #ffffff;
  --border: #222f47;
  --shadow: 0 4px 20px rgba(0, 0, 0, 0.2);
}

/* Structural Framework Resets */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; font-size: 16px; }
body { background-color: var(--bg-body); font-family: var(--font); color: var(--text-main); transition: background 0.3s, color 0.3s; line-height: 1.6; }
a { color: inherit; text-decoration: none; transition: all 0.25s; }
a:hover { color: var(--primary); }
img { max-width: 100%; height: auto; display: block; border-radius: var(--radius-sm); }
ul { list-style: none; }
button, input { font: inherit; background: none; border: none; outline: none; color: inherit; }

/* Grid Responsive System */
.container { max-width: var(--max-width); margin: 0 auto; padding: 0 20px; }
.row { display: grid; grid-template-columns: repeat(12, 1fr); gap: 24px; }
.col-8 { grid-column: span 8; }
.col-4 { grid-column: span 4; }
@media (max-width: 992px) { .col-8, .col-4 { grid-column: span 12; } }

/* Reading Progress Track Indicator */
#progress-bar { position: fixed; top: 0; left: 0; height: 4px; background: var(--primary); width: 0%; z-index: 10000; transition: width 0.1s; }

/* Premium Design Top Bar and Sticky Nav */
.topbar { background: #000; color: #fff; font-size: 13px; padding: 8px 0; font-weight: 500; }
.topbar .container { display: flex; justify-content: space-between; align-items: center; }
.live-dot-wrap { display: flex; align-items: center; gap: 8px; }
.live-dot { width: 8px; height: 8px; background: #ef4444; border-radius: 50%; animation: blink 1s infinite; }
@keyframes blink { 0%, 100% { opacity:1 } 50% { opacity:0.3 } }

header.sticky { position: sticky; top: 0; z-index: 999; box-shadow: var(--shadow); }
.header-main { background: var(--bg-card); border-bottom: 1px solid var(--border); padding: 16px 0; }
.header-main .container { display: flex; justify-content: space-between; align-items: center; }
.logo-title { font-size: 28px; font-weight: 800; color: var(--primary); margin: 0; }
.header-actions { display: flex; gap: 10px; align-items: center; }
.action-btn { width: 42px; height: 42px; background: var(--bg-body); border-radius: 50%; display: flex; align-items: center; justify-content: center; cursor: pointer; font-size: 18px; }
.action-btn:hover { background: var(--primary); color: #fff; }

/* Nav Links Area */
.main-nav { background: var(--bg-card); border-bottom: 1px solid var(--border); }
.nav-menu { display: flex; gap: 24px; }
.nav-menu > li { position: relative; }
.nav-menu a { display: block; padding: 14px 0; font-weight: 600; font-size: 15px; }
.nav-menu li::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 3px; background: var(--primary); transition: 0.3s; }
.nav-menu li:hover::after { width: 100%; }

/* Drawers and Modals */
#mobile-sidebar { position: fixed; top: 0; left: -280px; width: 280px; height: 100%; background: var(--bg-card); z-index: 10001; box-shadow: 10px 0 30px rgba(0,0,0,0.1); transition: 0.3s ease; padding: 24px; }
#mobile-sidebar.active { left: 0; }
.overlay { position: fixed; top:0; left:0; width:100%; height:100%; background:rgba(0,0,0,0.4); z-index:10000; display:none; }
.overlay.active { display:block; }

#search-popup { position: fixed; top: -100%; left: 0; width: 100%; background: var(--bg-card); z-index: 10002; padding: 30px 0; box-shadow: var(--shadow); transition: 0.4s ease; }
#search-popup.active { top: 0; }
.search-form-wrap { display: flex; max-width: 600px; margin: 0 auto; border: 2px solid var(--primary); border-radius: 30px; overflow: hidden; background: var(--bg-body); }
.search-form-wrap input { flex: 1; padding: 12px 20px; font-size: 16px; }
.search-form-wrap button { background: var(--primary); color: #fff; padding: 0 24px; font-weight: bold; cursor: pointer; }

/* News Ticker Components */
.breaking-news-bar { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); margin: 24px 0; display: flex; overflow: hidden; align-items: center; box-shadow: var(--shadow); }
.bn-label { background: var(--primary); color: #fff; padding: 12px 20px; font-weight: 700; font-size: 14px; position: relative; z-index: 2; white-space: nowrap; }
.bn-marquee { flex: 1; padding: 0 15px; font-size: 14px; font-weight: 500; }

/* Premium Responsive Hero Section */
.hero-slider-wrap { display: grid; grid-template-columns: 2fr 1fr; gap: 20px; margin-bottom: 30px; }
.hero-main-post { position: relative; border-radius: var(--radius-md); overflow: hidden; height: 420px; background: #000; }
.hero-main-post img { width: 100%; height: 100%; object-fit: cover; opacity: 0.75; transition: 0.5s; }
.hero-main-post:hover img { transform: scale(1.03); }
.hero-caption { position: absolute; bottom: 0; left: 0; padding: 30px; width: 100%; background: linear-gradient(transparent, rgba(0,0,0,0.9)); color: #fff; box-sizing: border-box; }
.badge-cat { background: var(--secondary); color: #fff; padding: 4px 10px; font-size: 12px; font-weight: bold; border-radius: var(--radius-sm); text-transform: uppercase; margin-bottom: 10px; display: inline-block; }
.hero-caption h2 { font-size: 28px; line-height: 1.3; font-weight: 700; margin-top: 5px; color: #fff; }
.hero-grid-side { display: flex; flex-direction: column; gap: 20px; }
.hero-side-item { background: var(--bg-card); padding: 15px; border-radius: var(--radius-md); display: flex; gap: 15px; box-shadow: var(--shadow); }
.hero-side-item img { width: 100px; height: 80px; object-fit: cover; border-radius: var(--radius-sm); }
@media (max-width: 768px) { .hero-slider-wrap { grid-template-columns: 1fr; } .hero-main-post { height: 300px; } }

/* Blogger Posts Dynamic Cards Architecture */
.latest-posts-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 24px; }
@media (max-width: 640px) { .latest-posts-grid { grid-template-columns: 1fr; } }
.post-card { background: var(--bg-card); border-radius: var(--radius-md); overflow: hidden; box-shadow: var(--shadow); transition: transform 0.3s, box-shadow 0.3s; display: flex; flex-direction: column; }
.post-card:hover { transform: translateY(-5px); box-shadow: var(--shadow-hover); }
.thumbnail-wrap { position: relative; overflow: hidden; padding-top: 56.25%; background: #eee; }
.thumbnail-wrap img { position: absolute; top: 0; left: 0; width: 100%; height: 100%; object-fit: cover; }
.post-card-content { padding: 20px; flex: 1; display: flex; flex-direction: column; justify-content: space-between; }
.post-card-content h3 { font-size: 18px; font-weight: 700; color: var(--heading); line-height: 1.4; margin-bottom: 10px; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
.post-meta { display: flex; align-items: center; gap: 12px; font-size: 12px; color: var(--text-muted); margin-bottom: 12px; }

/* Functional Modular Sidebar Elements */
.sidebar-wrap { display: flex; flex-direction: column; gap: 30px; }
.widget { background: var(--bg-card); padding: 24px; border-radius: var(--radius-md); box-shadow: var(--shadow); border: 1px solid var(--border); }
.widget-title { font-size: 16px; font-weight: 800; text-transform: uppercase; margin-bottom: 20px; border-left: 4px solid var(--primary); padding-left: 12px; color: var(--heading); letter-spacing: 0.5px; }
.sticky-sidebar { position: sticky; top: 90px; }

/* Monetization Slot Placeholders */
.ad-slot { background: rgba(var(--primary-rgb), 0.03); border: 1px dashed var(--border); text-align: center; padding: 15px; color: var(--text-muted); font-size: 12px; border-radius: var(--radius-sm); font-weight: 500; }

/* Premium Inner Article Framework Layout styling */
.post-body-wrap { background: var(--bg-card); padding: 35px; border-radius: var(--radius-lg); box-shadow: var(--shadow); }
.post-header h1 { font-size: 34px; font-weight: 800; line-height: 1.3; color: var(--heading); margin-bottom: 20px; }
@media(max-width: 640px) { .post-header h1 { font-size: 24px; } }
.post-body { font-size: 17px; line-height: 1.8; color: var(--text-main); margin-top: 25px; }
.post-body p { margin-bottom: 20px; }

/* In-Post Features UI */
.toc-box { background: var(--bg-body); border-radius: var(--radius-md); padding: 20px; margin: 25px 0; border: 1px solid var(--border); }
.toc-title { font-weight: 700; margin-bottom: 10px; display: flex; align-items: center; gap: 10px; }
.toc-list a { display: block; padding: 4px 0; color: var(--primary); font-size: 15px; }
.breadcrumb { display: flex; gap: 8px; font-size: 13px; color: var(--text-muted); margin-bottom: 15px; font-weight: 500; }
.share-bar { display: flex; gap: 10px; margin: 25px 0; flex-wrap: wrap; }
.share-btn-item { padding: 8px 16px; color: #fff; border-radius: var(--radius-sm); font-size: 13px; font-weight: 600; display: flex; align-items: center; gap: 8px; }
.share-tw { background: #1da1f2; } .share-wa { background: #25d366; } .share-tg { background: #0088cc; }

/* Profile Matrix Modules */
.author-box { background: var(--bg-body); border-radius: var(--radius-md); padding: 20px; display: flex; gap: 20px; margin-top: 40px; align-items: center; }
.author-avatar { width: 64px; height: 64px; border-radius: 50%; object-fit: cover; }
.related-posts-wrap { margin-top: 40px; }
.related-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; margin-top: 20px; }
@media(max-width: 640px) { .related-grid { grid-template-columns: 1fr; } }
.related-item img { border-radius: var(--radius-md); width: 100%; height: 120px; object-fit: cover; }
.related-item h4 { font-size: 14px; margin-top: 8px; font-weight: 600; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }

/* Premium Quad Layout Corporate Footer */
footer { background: #0c101a; color: #94a3b8; padding: 60px 0 20px; margin-top: 60px; font-size: 15px; border-top: 2px solid var(--border); }
footer h3 { color: #fff; font-size: 18px; font-weight: 700; margin-bottom: 20px; }
.footer-grid { display: grid; grid-template-columns: 2fr repeat(3, 1fr); gap: 40px; }
@media (max-width: 768px) { .footer-grid { grid-template-columns: 1fr; gap: 30px; } }
footer a:hover { color: #fff; }
.footer-bottom { border-top: 1px solid #1e293b; margin-top: 40px; padding-top: 25px; text-align: center; font-size: 14px; }

/* Floating UI Action Elements */
#backToTop { position: fixed; bottom: 30px; right: -60px; width: 46px; height: 46px; background: var(--primary); color: #fff; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 20px; cursor: pointer; box-shadow: 0 4px 15px rgba(0,0,0,0.2); z-index: 999; transition: right 0.3s; }
#backToTop.show { right: 30px; }

/* Pager Nav styling */
.blog-pager { display: flex; justify-content: space-between; margin: 30px 0; }
.blog-pager a { background: var(--bg-card); padding: 10px 20px; border-radius: var(--radius-sm); box-shadow: var(--shadow); font-weight: 600; font-size: 14px; border: 1px solid var(--border); }

/* Responsive Header Hidden Media Fixes */
@media (min-width: 993px) { #menuToggle { display: none !important; } }
@media (max-width: 992px) { .main-nav { display: none !important; } }

body.script:
document.addEventListener("DOMContentLoaded", function() {
  // 1. Live Calendar Locale Calculation Tracker Engine Module
  var dateBox = document.getElementById("liveDateDisplay");
  if(dateBox) {
      dateBox.textContent = new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  }

  // 2. High Speed Core Storage Dark Mode Controller Engine 
  var darkBtn = document.getElementById("darkToggle");
  if(darkBtn) {
      darkBtn.addEventListener("click", function() {
          document.body.classList.toggle("dark-mode");
          var isDark = document.body.classList.contains("dark-mode");
          localStorage.setItem("hadoti_dark_mode", isDark ? "enabled" : "disabled");
          darkBtn.textContent = isDark ? "☀️" : "🌙";
      });
      if(localStorage.getItem("hadoti_dark_mode") === "enabled") {
          document.body.classList.add("dark-mode");
          darkBtn.textContent = "☀️";
      }
  }

  // 3. Drawer Toggle Functional Navigation Core Matrix Modules Logic
  var menuToggle = document.getElementById("menuToggle");
  var closeMenu = document.getElementById("closeMenuBtn");
  var mobileSide = document.getElementById("mobile-sidebar");
  var overlay = document.getElementById("body-overlay");

  function toggleSidebarState() {
      if(mobileSide) mobileSide.classList.toggle("active");
      if(overlay) overlay.classList.toggle("active");
  }
  if(menuToggle) menuToggle.addEventListener("click", toggleSidebarState);
  if(closeMenu) closeMenu.addEventListener("click", toggleSidebarState);
  if(overlay) overlay.addEventListener("click", toggleSidebarState);

  // 4. Modal Dropdown Popup Search Box Visibility Controllers
  var searchToggle = document.getElementById("searchToggle");
  var searchBoxPop = document.getElementById("search-popup");
  if(searchToggle && searchBoxPop) {
      searchToggle.addEventListener("click", function(e) {
          e.stopPropagation();
          searchBoxPop.classList.toggle("active");
      });
      document.addEventListener("click", function(e) {
          if(!searchBoxPop.contains(e.target)) searchBoxPop.classList.remove("active");
      });
  }

  // 5. Kinetic Vector Animation Back To Top and Linear Page Progress Scrollers
  var btt = document.getElementById("backToTop");
  var progBar = document.getElementById("progress-bar");
  window.addEventListener("scroll", function() {
      var winScroll = document.body.scrollTop || document.documentElement.scrollTop;
      var height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
      var scrolled = (winScroll / height) * 100;
      if(progBar) progBar.style.width = scrolled + "%";

      if (winScroll > 400) { 
          if(btt) btt.classList.add("show"); 
      } else { 
          if(btt) btt.classList.remove("show"); 
      }
  });
  if(btt) {
      btt.addEventListener("click", function() {
          window.scrollTo({ top: 0, behavior: "smooth" });
      });
  }

  // 6. Automated Native Semantic Document Header Level Map Logic (TOC Engine)
  var articleContainer = document.getElementById("blogPostMainContent");
  var tocBox = document.getElementById("tocContainer");
  var tocList = document.getElementById("tocTargetList");
  if(articleContainer && tocBox && tocList) {
      var headings = articleContainer.querySelectorAll("h2, h3");
      if(headings.length > 1) {
          tocBox.style.display = "block";
          headings.forEach(function(heading, idx) {
              var id = "toc_head_" + idx;
              heading.setAttribute("id", id);
              var li = document.createElement("a");
              li.setAttribute("href", "#" + id);
              li.textContent = (idx + 1) + ". " + heading.textContent;
              li.style.paddingLeft = heading.tagName.toLowerCase() === "h3" ? "15px" : "0px";
              tocList.appendChild(li);
          });
      }
  }

  // 7. Text Metrics Velocity Dynamic Word Count Velocity Processor Engine Loop
  if(articleContainer) {
      var textBlocks = articleContainer.innerText || articleContainer.textContent;
      var wordsCount = textBlocks.trim().split(/\s+/).length;
      var readTimeCalculated = Math.ceil(wordsCount / 220);
      var labelTextHolder = document.getElementById("readTimeCalc");
      if(labelTextHolder) labelTextHolder.textContent = readTimeCalculated + " Min Read";
  }
});
